# REST API ステージ内のすべてのメソッドの実行ログを有効にします
resource "aws_api_gateway_method_settings" "<example_resource_name>" {
  rest_api_id = "<example_resource_id>"
  stage_name  = "<example_resource_name>"
  method_path = "*/*"
  settings {
    logging_level = "ERROR"  # 重要：ステージ実行ログを有効にします
  }
}
